curl -s -H "Authorization: Bearer $(cat /home/gilles/.openclaw/credentials/notion)" \
  -H "Notion-Version: 2022-06-28" \
  "https://api.notion.com/v1/pages/310ddac9-bdfc-81fb-9666-c89d427d0743" | python3 -c "
import sys, json
data = json.load(sys.stdin)
props = data.get('properties', {})
for k, v in props.items():
    vtype = v.get('type','')
    if vtype == 'title':
        val = ''.join([t.get('plain_text','') for t in v.get('title',[])])
    elif vtype == 'rich_text':
        val = ''.join([t.get('plain_text','') for t in v.get('rich_text',[])])
    elif vtype == 'select':
        sel = v.get('select')
        val = sel.get('name','') if sel else ''
    elif vtype == 'status':
        sel = v.get('status')
        val = sel.get('name','') if sel else ''
    elif vtype == 'date':
        d = v.get('date')
        val = d.get('start','') if d else ''
    elif vtype == 'checkbox':
        val = str(v.get('checkbox',''))
    else:
        val = str(vtype)
    if val:
        print(f'{k}: {val}')
" 2>/dev/null

